const msg = $input.first().json;
const chatId = String(
  msg.message?.chat?.id ||
  msg.channel_post?.chat?.id ||
  ''
);
const text = (
  msg.message?.text ||
  msg.channel_post?.text ||
  ''
).trim();
const isNew = text.toLowerCase() === '/new';

const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};

const prev = staticData.sessions[chatId];
const prevNum = typeof prev === 'number' && Number.isFinite(prev) ? prev : 0;

if (isNew || prevNum === 0) {
  staticData.sessions[chatId] = prevNum + 1;
}

const sessionNum = staticData.sessions[chatId];
const sessionKey = `chat_${chatId}_s${sessionNum}`;

return [{
  json: {
    chatId,
    text,
    isNew,
    sessionKey
  }
}];

const httpItem = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.promptCache) staticData.promptCache = {};
const AGENT_ID = 'a1';
const CACHE_KEY = `prompt_cache_${AGENT_ID}`;
const TTL_MS = 5 * 60 * 1000;
const now = Date.now();
const rawBody = httpItem.data ?? httpItem.body;
const body = typeof rawBody === 'string' ? rawBody : '';
const httpOk = httpItem.statusCode === 200 && body.trim().length > 100;
let prompt;
let source;
if (httpOk) {
  prompt = body;
  staticData.promptCache[CACHE_KEY] = { prompt, ts: now };
  source = 'live';
} else {
  const cached = staticData.promptCache[CACHE_KEY];
  if (!cached || !cached.prompt) {
    throw new Error(`[${AGENT_ID}] Prompt fetch failed (status ${httpItem.statusCode}) and no cache available`);
  }
  prompt = cached.prompt;
  const ageMin = Math.round((now - cached.ts) / 60000);
  source = (now - cached.ts) > TTL_MS ? 'cache-stale' : 'cache';
  console.log(`[${AGENT_ID}] FALLBACK: HTTP ${httpItem.statusCode}, serving cached prompt (age ${ageMin}m, source=${source})`);
}
return [{ json: { prompt, source, agent: AGENT_ID, promptLen: prompt.length } }];

const agentOutput = $input.first().json.output || $input.first().json.text || $input.first().json.response || '';
const chatId = $('Extract Context').item.json.chatId;

const xmlMatch = agentOutput.match(/<JobDescription>[\s\S]*?<\/JobDescription>/);
const xmlContent = xmlMatch ? xmlMatch[0] : null;

let jsonContent = null;
const jsonBlockMatch = agentOutput.match(/```json\s*([\s\S]*?)```/);
if (jsonBlockMatch) {
  jsonContent = jsonBlockMatch[1].trim();
} else {
  const bareJsonMatch = agentOutput.match(/(\{[\s\S]*?"id"\s*:\s*"a\d+"[\s\S]*?\})/);
  if (bareJsonMatch) jsonContent = bareJsonMatch[1].trim();
}

let textContent = agentOutput;
if (xmlContent) textContent = textContent.replace(xmlContent, '');
if (jsonBlockMatch) textContent = textContent.replace(jsonBlockMatch[0], '');
else if (jsonContent) textContent = textContent.replace(jsonContent, '');
textContent = textContent.replace(/```json|```/g, '').trim();

return [{
  json: {
    chatId,
    textContent,
    xmlContent,
    jsonContent,
    hasFiles: !!(xmlContent || jsonContent),
    fullOutput: agentOutput
  }
}];

const MAX = 4000;
const fullOutput = $('Parse Output').first().json.fullOutput || '';
const chatId = $('Extract Context').first().json.chatId;

function splitText(text, max) {
  if (!text) return [''];
  if (text.length <= max) return [text];
  const parts = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= max) {
      parts.push(remaining);
      break;
    }
    let sliceEnd = max;
    const lastDouble = remaining.lastIndexOf('\n\n', max);
    const lastSingle = remaining.lastIndexOf('\n', max);
    const lastSpace = remaining.lastIndexOf(' ', max);
    if (lastDouble > max * 0.5) sliceEnd = lastDouble;
    else if (lastSingle > max * 0.5) sliceEnd = lastSingle;
    else if (lastSpace > max * 0.5) sliceEnd = lastSpace;
    parts.push(remaining.slice(0, sliceEnd).trimEnd());
    remaining = remaining.slice(sliceEnd).trimStart();
  }
  return parts;
}

return splitText(fullOutput, MAX).map(chunk => ({
  json: { chatId, chunk }
}));

const raw = $('Parse Output').first().json.jsonContent || '';
const chatId = $('Parse Output').first().json.chatId;

let draft = {};
try {
  draft = JSON.parse(raw);
} catch (e) {
  throw new Error('Failed to parse JSON draft from Sarah: ' + e.message + ' | raw: ' + raw.slice(0, 200));
}

const required = ['name','id','role','function','model','interface','orchestration','personality','age','race','gender','particulars','notes','spec'];
for (const key of required) {
  if (!draft[key]) draft[key] = '';
}

const headshotPrompt = `Create a high-resolution, professional corporate headshot of a ${draft.age} ${draft.race} ${draft.gender} ${draft.particulars}. The subject is dressed in clean, modern business attire and has a warm, confident expression. The background is a blurred minimalist office setting. The image uses soft studio lighting, sharp focus on the eyes, 8k quality, and has photorealistic skin textures.`;

return [{
  json: {
    chatId,
    headshotPrompt,
    draft
  }
}];

const headshotJson = $('Generate Headshot').first().json || {};
const b64 = headshotJson.data?.[0]?.b64_json || '';
if (!b64) throw new Error('No b64_json in Generate Headshot response: ' + JSON.stringify(headshotJson).slice(0, 500));

return [{
  json: $('Parse JSON Draft').first().json,
  binary: {
    headshot: {
      data: b64,
      mimeType: 'image/png',
      fileName: 'headshot.png',
      fileExtension: 'png'
    }
  }
}];

const draft = $('Parse JSON Draft').first().json.draft;
const chatId = $('Parse JSON Draft').first().json.chatId;
const uploadId = $('Create File Upload').first().json.id;

const registryData = $('Query Registry').first().json || {};
const results = registryData.results || [];
let maxN = 0;
for (const page of results) {
  const idProp = page.properties?.ID;
  if (!idProp || !Array.isArray(idProp.rich_text)) continue;
  const idString = idProp.rich_text.map(r => r.plain_text || '').join('');
  const match = idString.match(/^a(\d+)$/);
  if (match) {
    const n = parseInt(match[1], 10);
    if (n > maxN) maxN = n;
  }
}
const nextId = `a${maxN + 1}`;

function rt(value) {
  return { rich_text: [{ type: 'text', text: { content: String(value || '').slice(0, 1900) } }] };
}
function sel(value) {
  return value ? { select: { name: String(value) } } : undefined;
}
function chunkSpec(text, chunkSize) {
  const chunks = [];
  const s = String(text || '');
  for (let i = 0; i < s.length; i += chunkSize) {
    chunks.push({ type: 'text', text: { content: s.slice(i, i + chunkSize) } });
  }
  return chunks;
}
const specRichText = chunkSpec(draft.spec, 1900);

const properties = {
  'Name': { title: [{ type: 'text', text: { content: String(draft.name || 'Unnamed agent') } }] },
  'ID': rt(nextId),
  'Role': rt(draft.role),
  'Function': rt(draft.function),
  'Model': rt(draft.model),
  'Personality': rt(draft.personality),
  'Age': rt(draft.age),
  'Race': rt(draft.race),
  'Gender': rt(draft.gender),
  'Particulars': rt(draft.particulars),
  'Notes': rt(draft.notes),
  'Status': { select: { name: 'planned' } },
  'Profile Picture': {
    files: [{ type: 'file_upload', name: 'headshot.png', file_upload: { id: uploadId } }]
  }
};
const iface = sel(draft.interface); if (iface) properties['Interface'] = iface;
const orch = sel(draft.orchestration); if (orch) properties['Orchestration'] = orch;

const body = {
  parent: { database_id: 'b3f81c65-8bd5-4bf6-8a3e-9805f6c2f9ec' },
  properties,
  children: specRichText.length ? [{
    object: 'block',
    type: 'code',
    code: {
      language: 'xml',
      rich_text: specRichText
    }
  }] : []
};

return [{ json: { chatId, body, draft, nextId } }];

const response = $input.first().json;
const chatId = $('Parse JSON Draft').first().json.chatId;
const draft = $('Parse JSON Draft').first().json.draft;
const nextId = $('Build Notion Body').first().json.nextId || 'aN';
const pageUrl = response.url || response.public_url || '';
const name = draft.name || 'the new agent';

const text = pageUrl
  ? `Profile created for ${name} (${nextId}).

${pageUrl}

Tell Claude Code to build the agent from this Notion page.`
  : `Notion draft created but no URL was returned. Response: ${JSON.stringify(response).slice(0, 500)}`;

return [{ json: { chatId, chunk: text } }];
